SELECT AVG(new_cases) AS avg_new_cases_last_7_days
FROM daily_stats
WHERE fips = 0;

SELECT total_cases, case_fatality_rate
FROM daily_stats
WHERE fips = 1 AND date = '1';

SELECT total_covid_hosp, hosp_fatality_rate
FROM hospitalization_data
WHERE fips = 1 AND date = '1';

SELECT SUM(new_cases) AS total_new_cases
FROM daily_stats
WHERE date = '2023-10-01';

SELECT county
FROM counties
ORDER BY state, county;

SELECT SUM(new_cases) AS total_new_cases
FROM daily_stats
WHERE fips = 1 AND date = '1';

